import{_ as l,o,c as t,a3 as r}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"审批策略与交互","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/tool-calling/approval-strategy.md","filePath":"user-guide/tools/llm-chat/tool-calling/approval-strategy.md","lastUpdated":1778239080000}'),e={name:"user-guide/tools/llm-chat/tool-calling/approval-strategy.md"};function i(n,a,s,u,g,d){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="审批策略与交互" tabindex="-1">审批策略与交互 <a class="header-anchor" href="#审批策略与交互" aria-label="Permalink to &quot;审批策略与交互&quot;">​</a></h1><p>为了在便利性与安全性之间取得平衡，系统为工具调用提供了灵活的审批机制。</p><h2 id="审批模式-mode" tabindex="-1">审批模式 (Mode) <a class="header-anchor" href="#审批模式-mode" aria-label="Permalink to &quot;审批模式 (Mode)&quot;">​</a></h2><p>你可以在智能体编辑器的“工具调用”面板中切换执行模式：</p><h3 id="_1-自动模式-auto" tabindex="-1">1. 自动模式 (Auto) <a class="header-anchor" href="#_1-自动模式-auto" aria-label="Permalink to &quot;1. 自动模式 (Auto)&quot;">​</a></h3><ul><li><strong>行为</strong>：系统会尝试自动执行工具调用。</li><li><strong>精细控制</strong>：即使在自动模式下，只有在“自动批准列表”中勾选的工具/方法才会被静默执行。</li><li><strong>未授权处理</strong>：如果模型请求了一个未在自动批准列表中的工具，系统会回退到 UI 拦截，等待用户手动点击。</li></ul><h3 id="_2-手动模式-manual" tabindex="-1">2. 手动模式 (Manual) <a class="header-anchor" href="#_2-手动模式-manual" aria-label="Permalink to &quot;2. 手动模式 (Manual)&quot;">​</a></h3><ul><li><strong>行为</strong>：所有工具调用（无论是否在白名单中）都必须经过用户手动确认。</li><li><strong>适用场景</strong>：涉及高风险操作（如删除文件、执行系统命令）或需要严格审计的场景。</li></ul><h2 id="ui-交互-toolcallingapprovalbar" tabindex="-1">UI 交互：ToolCallingApprovalBar <a class="header-anchor" href="#ui-交互-toolcallingapprovalbar" aria-label="Permalink to &quot;UI 交互：ToolCallingApprovalBar&quot;">​</a></h2><p>当工具调用需要审批时，聊天界面底部会弹出审批栏：</p><ul><li><strong>参数预览</strong>：点击工具名称可以查看模型生成的调用参数。</li><li><strong>单条批准</strong>：点击“批准”执行该特定调用。</li><li><strong>拒绝</strong>：点击“拒绝”将向模型反馈“用户拒绝了此操作”的信息，模型通常会据此调整后续回复。</li><li><strong>全部批准</strong>：在并行调用多个工具时，可以一键通过所有请求。</li></ul><h2 id="白名单管理" tabindex="-1">白名单管理 <a class="header-anchor" href="#白名单管理" aria-label="Permalink to &quot;白名单管理&quot;">​</a></h2><p>在智能体配置中，你可以针对具体的方法进行配置：</p><ul><li><strong>工具开关</strong>：完全禁用某个工具。</li><li><strong>方法开关</strong>：禁用工具内的特定功能（例如：允许读取文件，但禁止写入文件）。</li><li><strong>自动批准勾选</strong>：将常用且安全的查询类操作设为自动批准，提升对话流畅度。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./">工具调用概览</a></li><li><a href="./tool-definition">工具定义与宏注入</a></li></ul>',17)])])}const c=l(e,[["render",i]]);export{p as __pageData,c as default};
